import BotonTema from "../reutilizables/botonTema";
import Header2 from "../reutilizables/header2";
import Footer from "../reutilizables/footer";
import gitHub from "../reutilizables/github";

function Inicio() {
  return (
    <div>
      <div id="tema">
        <BotonTema />
      </div>
      <div id="container">
        <header id="header1"></header>
        <Header2 />

        <section id="content">
          <p>
            Bienvenido al sistema de Cuentas DJ, de click al boton para iniciar
            sesion⬇️:
          </p>

          <button id="sesion" class="principales">
            iniciar sesion
          </button>
        </section>
      </div>
      <Footer />
    </div>
  );
}

export default Inicio;
